export interface ImageData {
  id: string;
  file: File;
  preview: string;
  status: 'pending' | 'processing' | 'completed' | 'failed';
  metadata?: PhotoMetadata;
  error?: string;
}

export interface PhotoMetadata {
  title: string;
  keywords: string; // Comma separated list for CSV
}

export interface ApiResponse {
  title: string;
  keywords: string[];
}

export enum AppState {
  SPLASH = 'SPLASH',
  HOME = 'HOME',
  PROCESSING = 'PROCESSING',
  RESULTS = 'RESULTS'
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ApiResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are an elite Adobe Stock Metadata Optimization Specialist. Your task is to analyze visual content with an expert eye for commercial stock photography appeal and SEO performance.

Task: Generate highly optimized, distinct metadata for the provided image.

Output Requirements:
Title (90-120 Characters):
- Create a compelling, detailed title.
- Ensure the title length is strictly between 90 and 120 characters.
- Focus on the main subject, action, context, environment, emotion, and aesthetic qualities (e.g., lighting, composition).
- Avoid all punctuation (commas, periods, exclamation marks, etc.) within the title.
- Keywords should be naturally integrated, not just a list.

Keywords (40 Keywords):
- Generate exactly 40 keywords.
- Relevance First: The first 10-15 keywords must be the most critical and directly descriptive of the image's primary elements.
- Include a strong mix of:
  Literal: Objects, colors, locations, people, actions.
  Conceptual: Emotions, themes (e.g., innovation, growth, tranquility, struggle, diversity, future).
  Technical: Lighting (e.g., "natural light", "backlit"), composition (e.g., "close up", "wide shot").
- Keywords should be single words or very short, natural phrases (max 3 words).
- All keywords must be comma-separated.

Constraints:
- Do NOT include any additional text, conversational phrases, or explanations outside the JSON block.
- Do NOT use generic terms like "photo", "image", "picture", "stock", "isolated", or "background".
- Ensure the JSON is perfectly valid.`;

export async function generatePhotoMetadata(base64Image: string, mimeType: string): Promise<ApiResponse> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image,
              mimeType: mimeType,
            },
          },
          {
            text: "Generate stock photography metadata in JSON format as requested.",
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: {
              type: Type.STRING,
              description: "Optimized title, 90-120 characters, no punctuation",
            },
            keywords: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Array of exactly 40 keywords",
            },
          },
          required: ["title", "keywords"],
        },
      },
    });

    const text = response.text || '';
    return JSON.parse(text) as ApiResponse;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
}

import { ImageData } from "../types";

export const fileToBase64 = (file: File): Promise<{ base64: string; mimeType: string }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve({ base64, mimeType: file.type });
    };
    reader.onerror = (error) => reject(error);
  });
};

export const downloadCSV = (data: ImageData[]) => {
  const headers = ["Filename", "Title", "Keywords"];
  const rows = data
    .filter(img => img.status === 'completed' && img.metadata)
    .map(img => [
      img.file.name,
      `"${img.metadata?.title.replace(/"/g, '""')}"`,
      `"${img.metadata?.keywords.replace(/"/g, '""')}"`
    ]);

  const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `OSMAN_Metadata_${new Date().getTime()}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

