import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { AppState, ImageData, PhotoMetadata } from './types';
import { Logo } from './components/Logo';
import { fileToBase64, downloadCSV } from './utils/fileUtils';
import { generatePhotoMetadata } from './services/geminiService';

export default function App() {
  const [appState, setAppState] = useState<AppState>(AppState.SPLASH);
  const [images, setImages] = useState<ImageData[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);
  const stopRequested = useRef(false);

  // Splash Screen timer
  useEffect(() => {
    const timer = setTimeout(() => {
      setAppState(AppState.HOME);
    }, 2500);
    return () => clearTimeout(timer);
  }, []);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const selectedFiles = Array.from(e.target.files) as File[];
    const newImages: ImageData[] = selectedFiles.slice(0, 500).map((file, index) => ({
      id: `${Date.now()}-${index}`,
      file,
      preview: URL.createObjectURL(file),
      status: 'pending'
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const startProcessing = async () => {
    if (images.length === 0) return;
    setAppState(AppState.PROCESSING);
    setIsProcessing(true);
    stopRequested.current = false;

    for (let i = 0; i < images.length; i++) {
      if (stopRequested.current) break;

      const img = images[i];
      if (img.status !== 'pending') continue;

      setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'processing' } : item));

      try {
        const { base64, mimeType } = await fileToBase64(img.file);
        const result = await generatePhotoMetadata(base64, mimeType);

        const metadata: PhotoMetadata = {
          title: result.title,
          keywords: result.keywords.join(', ')
        };

        setImages(prev => prev.map(item => item.id === img.id ? { 
          ...item, 
          status: 'completed', 
          metadata 
        } : item));
      } catch (err) {
        setImages(prev => prev.map(item => item.id === img.id ? { 
          ...item, 
          status: 'failed', 
          error: (err as Error).message 
        } : item));
      }
    }

    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const cancelProcessing = () => {
    stopRequested.current = true;
    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const reset = () => {
    setImages([]);
    setSearchTerm('');
    setAppState(AppState.HOME);
  };

  const copyToClipboard = (text: string, type: string) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(type);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  const filteredImages = useMemo(() => {
    return images.filter(img => 
      img.file.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [images, searchTerm]);

  if (appState === AppState.SPLASH) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-deep-navy animate-pulse">
        <Logo size="lg" />
        <h1 className="mt-8 text-4xl font-title font-bold tracking-widest text-white">OSMAN Metadata</h1>
        <p className="mt-4 text-[#cccccc] font-medium italic">Developed by Abdullah Al Osman</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-deep-navy flex flex-col font-sans text-white">
      {/* Header */}
      <header className="p-6 border-b border-[#0f3460] flex items-center justify-between sticky top-0 bg-deep-navy z-50">
        <div className="flex items-center gap-4">
           <Logo size="sm" />
           <div>
            <h1 className="text-2xl font-title font-bold">OSMAN Metadata</h1>
            <p className="text-light-gray text-xs">AI-Powered Stock Photo SEO</p>
          </div>
        </div>

        {appState === AppState.RESULTS && (
           <div className="hidden md:block relative">
              <input 
                type="text" 
                placeholder="Search results..." 
                className="bg-[#0f3460] border border-white/10 rounded-full px-5 py-2 text-sm focus:border-[#e94560] outline-none w-64 transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
              <svg className="w-4 h-4 absolute right-4 top-2.5 text-light-gray" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
           </div>
        )}
      </header>

      {/* Toast Feedback */}
      {copyFeedback && (
        <div className="fixed top-24 left-1/2 transform -translate-x-1/2 bg-[#e94560] text-white px-6 py-2 rounded-full shadow-2xl z-[100] font-bold animate-bounce">
          {copyFeedback} Copied!
        </div>
      )}

      {/* Main Content Area */}
      <main className="flex-grow container mx-auto px-4 py-8">

        {appState === AppState.HOME && (
          <div className="max-w-4xl mx-auto mt-12">
            <div className="bg-[#0f3460] rounded-2xl p-16 border-2 border-dashed border-[#e94560] border-opacity-30 text-center transition-all hover:border-opacity-100 flex flex-col items-center shadow-2xl">
              <div className="mb-8 p-8 bg-deep-navy rounded-full border border-white/5 shadow-inner">
                <svg className="w-16 h-16 text-[#e94560]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                </svg>
              </div>
              <h2 className="text-3xl font-title font-bold mb-3">Optimize Your Stock Workflow</h2>
              <p className="text-light-gray mb-10 max-w-md">Drop your high-res photos here to generate SEO-perfect titles and keywords automatically.</p>

              <label className="bg-accent-red hover:bg-[#c83a52] text-white px-12 py-5 rounded-full font-bold text-xl cursor-pointer transition-all shadow-xl hover:scale-105 active:scale-95 shadow-red-900/40">
                Select Images
                <input type="file" multiple accept="image/*" className="hidden" onChange={handleFileSelect} />
              </label>

              {images.length > 0 && (
                <div className="mt-12 text-center animate-fade-in">
                  <div className="bg-deep-navy/50 px-6 py-2 rounded-full inline-block border border-white/5 mb-6">
                    <span className="font-bold text-xl accent-red">{images.length}</span> images ready for batch
                  </div>
                  <button 
                    onClick={startProcessing}
                    className="w-full bg-white text-[#0f3460] font-title font-bold px-10 py-4 rounded-xl hover:bg-gray-200 transition-all flex items-center justify-center gap-3 shadow-xl"
                  >
                    <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                    Start Processing Batch
                  </button>
                </div>
              )}
            </div>
          </div>
        )}

        {appState === AppState.PROCESSING && (
          <div className="max-w-2xl mx-auto flex flex-col items-center mt-8">
            <div className="relative w-72 h-72 mb-16">
              <svg className="w-full h-full transform -rotate-90">
                <circle cx="144" cy="144" r="130" stroke="#0f3460" strokeWidth="16" fill="transparent" />
                <circle
                  cx="144" cy="144" r="130" stroke="#e94560" strokeWidth="16" fill="transparent"
                  strokeDasharray={816}
                  strokeDashoffset={816 - (816 * images.filter(img => img.status === 'completed' || img.status === 'failed').length) / images.length}
                  strokeLinecap="round"
                  className="transition-all duration-700 ease-out"
                />
              </svg>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-5xl font-bold font-title drop-shadow-lg">
                  {Math.round((images.filter(img => img.status === 'completed' || img.status === 'failed').length / images.length) * 100)}%
                </span>
                <span className="text-xs uppercase tracking-widest text-light-gray mt-2">Overall Progress</span>
              </div>
            </div>

            <div className="w-full bg-[#0f3460] rounded-2xl p-6 border border-white/5 shadow-2xl overflow-hidden">
               <div className="flex justify-between items-center mb-6">
                  <h3 className="text-xl font-bold font-title">Processing Queue</h3>
                  <span className="text-sm bg-deep-navy px-3 py-1 rounded-full border border-white/5">
                    {images.filter(img => img.status === 'completed').length} Successful
                  </span>
               </div>
              <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                {images.map(img => (
                  <div key={img.id} className="bg-deep-navy/60 p-4 rounded-xl flex items-center justify-between border border-white/5 backdrop-blur-sm">
                    <div className="flex items-center gap-4 overflow-hidden">
                      <div className="relative">
                        <img src={img.preview} alt="preview" className="w-12 h-12 object-cover rounded-lg ring-1 ring-white/10" />
                        {img.status === 'processing' && (
                          <div className="absolute inset-0 flex items-center justify-center bg-black/40 rounded-lg">
                            <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                          </div>
                        )}
                      </div>
                      <div className="flex flex-col">
                        <span className="text-sm font-medium truncate w-48">{img.file.name}</span>
                        <span className={`text-[10px] font-bold uppercase tracking-widest ${
                          img.status === 'completed' ? 'text-green-400' :
                          img.status === 'failed' ? 'text-red-400' :
                          img.status === 'processing' ? 'text-blue-400' : 'text-gray-500'
                        }`}>
                          {img.status}
                        </span>
                      </div>
                    </div>
                    {img.status === 'completed' && (
                       <svg className="w-6 h-6 text-green-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <button 
              onClick={cancelProcessing}
              className="mt-10 bg-white/10 hover:bg-white/20 text-white px-10 py-3 rounded-full font-bold transition-all flex items-center gap-2 border border-white/10"
            >
              Cancel Generation
            </button>
          </div>
        )}

        {appState === AppState.RESULTS && (
          <div className="max-w-7xl mx-auto animate-fade-in">
            <div className="bg-[#0f3460] rounded-3xl p-8 mb-10 border border-white/5 shadow-2xl flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="text-center md:text-left">
                <h2 className="text-4xl font-title font-bold mb-2">Generation Complete!</h2>
                <p className="text-light-gray">
                  Processed <span className="text-white font-bold">{images.length}</span> items. 
                  Ready for Adobe Stock / Contributor portal.
                </p>
              </div>
              <div className="flex flex-wrap justify-center gap-4">
                <button 
