                  className="bg-accent-red hover:bg-[#c83a52] text-white px-8 py-4 rounded-2xl font-bold flex items-center gap-3 shadow-xl transition-all hover:scale-105 active:scale-95"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  Export Data (CSV)
                </button>
                <button 
                  onClick={reset}
                  className="bg-deep-navy hover:bg-black/40 text-white px-8 py-4 rounded-2xl font-bold flex items-center gap-3 transition-all border border-white/10"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                  Start New Project
                </button>
              </div>
            </div>

            {/* Mobile Search */}
            <div className="md:hidden mb-6">
               <input 
                type="text" 
                placeholder="Search by filename..." 
                className="w-full bg-[#0f3460] border border-white/10 rounded-xl px-5 py-4 outline-none focus:border-[#e94560]"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
              {filteredImages.map(img => (
                <div key={img.id} className="bg-[#0f3460] rounded-2xl overflow-hidden flex flex-col border border-white/10 hover:border-[#e94560]/50 transition-all group shadow-xl">
                  {/* Card Image Area */}
                  <div className="relative h-56 overflow-hidden">
                    <img src={img.preview} alt="preview" className="w-full h-full object-cover transition-transform group-hover:scale-105 duration-500" />
                    <div className="absolute top-4 left-4 bg-black/60 backdrop-blur-md px-3 py-1 rounded-full border border-white/10">
                      <span className="text-[10px] font-bold tracking-widest text-white/80 uppercase truncate max-w-[120px] block">
