{
  "name": "osman-metadata",
  "version": "1.0.0",
  "description": "AI-Powered Stock Photo SEO metadata generator.",
  "main": "main.js",
  "author": "Abdullah Al Osman",
  "scripts": {
    "start": "electron .",
    "build": "electron-builder --win"
  },
  "devDependencies": {
    "electron": "^31.0.0",
    "electron-builder": "^24.13.3"
  },
  "build": {
    "appId": "com.osman.metadata",
    "productName": "OSMAN Metadata",
    "win": {
      "target": "portable",
      "artifactName": "OSMAN_Metadata.exe"
    },
    "directories": {
      "output": "dist"
    }
  }
}

const { app, BrowserWindow } = require('electron');
const path = require('path');

function createWindow() {
  const win = new BrowserWindow({
    width: 1300,
    height: 900,
    backgroundColor: '#1a1a2e',
    show: false,
    webPreferences: {
      nodeIntegration: true,
      contextIsolation: false,
    }
  });

  // Load the index.html
  win.loadFile('index.html');

  // Hide the default menu bar for a cleaner UI
  win.setMenuBarVisibility(false);

  win.once('ready-to-show', () => {
    win.show();
  });
}

app.whenReady().then(createWindow);

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit();
  }
});

app.on('activate', () => {
  if (BrowserWindow.getAllWindows().length === 0) {
    createWindow();
  }
});

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { AppState, ImageData, PhotoMetadata } from './types';
import { Logo } from './components/Logo';
import { fileToBase64, downloadCSV } from './utils/fileUtils';
import { generatePhotoMetadata } from './services/geminiService';

export default function App() {
  const [appState, setAppState] = useState<AppState>(AppState.SPLASH);
  const [images, setImages] = useState<ImageData[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);
  const stopRequested = useRef(false);

  // Splash Screen timer
  useEffect(() => {
    const timer = setTimeout(() => {
      setAppState(AppState.HOME);
    }, 2500);
    return () => clearTimeout(timer);
  }, []);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const selectedFiles = Array.from(e.target.files) as File[];
    const newImages: ImageData[] = selectedFiles.slice(0, 500).map((file, index) => ({
      id: `${Date.now()}-${index}`,
      file,
      preview: URL.createObjectURL(file),
      status: 'pending'
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const startProcessing = async () => {
    if (images.length === 0) return;
    setAppState(AppState.PROCESSING);
    setIsProcessing(true);
    stopRequested.current = false;

    for (let i = 0; i < images.length; i++) {
      if (stopRequested.current) break;

      const img = images[i];
      if (img.status !== 'pending') continue;

      setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'processing' } : item));

      try {
        const { base64, mimeType } = await fileToBase64(img.file);
        const result = await generatePhotoMetadata(base64, mimeType);

        const metadata: PhotoMetadata = {
          title: result.title,
          keywords: result.keywords.join(', ')
        };

        setImages(prev => prev.map(item => item.id === img.id ? { 
          ...item, 
          status: 'completed', 
          metadata 
        } : item));
      } catch (err) {
        setImages(prev => prev.map(item => item.id === img.id ? { 
          ...item, 
          status: 'failed', 
          error: (err as Error).message 
        } : item));
      }
    }

    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const cancelProcessing = () => {
    stopRequested.current = true;
    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const reset = () => {
    setImages([]);
    setSearchTerm('');
    setAppState(AppState.HOME);
  };

  const copyToClipboard = (text: string, type: string) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(type);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  const filteredImages = useMemo(() => {
    return images.filter(img => 
      img.file.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [images, searchTerm]);

  if (appState === AppState.SPLASH) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-deep-navy animate-pulse">
        <Logo size="lg" />
        <h1 className="mt-8 text-4xl font-title font-bold tracking-widest text-white">OSMAN Metadata</h1>
        <p className="mt-4 text-[#cccccc] font-medium italic">Developed by Abdullah Al Osman</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-deep-navy flex flex-col font-sans text-white">
      {/* Desktop Header */}
      <header className="p-6 border-b border-[#0f3460] flex items-center justify-between sticky top-0 bg-deep-navy z-50 shadow-lg">
        <div className="flex items-center gap-4">
           <Logo size="sm" />
           <div>
            <h1 className="text-2xl font-title font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-[#00d2ff]">OSMAN Metadata</h1>
            <p className="text-light-gray text-xs flex items-center gap-2">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              Desktop Engine Ready
            </p>
          </div>
        </div>

        {appState === AppState.RESULTS && (
           <div className="hidden md:block relative">
              <input 
                type="text" 
                placeholder="Search results..." 
                className="bg-[#0f3460] border border-white/10 rounded-full px-5 py-2 text-sm focus:border-[#e94560] outline-none w-64 transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
              <svg className="w-4 h-4 absolute right-4 top-2.5 text-light-gray" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
           </div>
        )}
      </header>

      {/* Toast Feedback */}
      {copyFeedback && (
        <div className="fixed top-24 left-1/2 transform -translate-x-1/2 bg-[#e94560] text-white px-6 py-2 rounded-full shadow-2xl z-[100] font-bold animate-bounce border border-white/20">
          {copyFeedback} Copied!
        </div>
