    </div>
  );
}

{
  "name": "OSMAN Metadata",
  "description": "Professional AI-Powered Stock Photo SEO metadata generator. Optimized for Adobe Stock and Shutterstock contributors. Developed by Abdullah Al Osman.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { AppState, ImageData, PhotoMetadata } from './types';
import { Logo } from './components/Logo';
import { fileToBase64, downloadCSV } from './utils/fileUtils';
import { generatePhotoMetadata } from './services/geminiService';

export default function App() {
  const [appState, setAppState] = useState<AppState>(AppState.SPLASH);
  const [images, setImages] = useState<ImageData[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);
  const stopRequested = useRef(false);

  // Splash Screen timer
  useEffect(() => {
    const timer = setTimeout(() => {
      setAppState(AppState.HOME);
    }, 2800);
    return () => clearTimeout(timer);
  }, []);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const selectedFiles = Array.from(e.target.files) as File[];

    // Validate file count
    if (images.length + selectedFiles.length > 500) {
      alert("Maximum 500 images allowed per batch.");
      return;
    }

    const newImages: ImageData[] = selectedFiles.map((file, index) => ({
      id: `${Date.now()}-${index}`,
      file,
      preview: URL.createObjectURL(file),
      status: 'pending'
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const startProcessing = async () => {
    if (images.length === 0) return;
    setAppState(AppState.PROCESSING);
    setIsProcessing(true);
    stopRequested.current = false;

    for (let i = 0; i < images.length; i++) {
      if (stopRequested.current) break;

      const img = images[i];
      if (img.status !== 'pending') continue;

      setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'processing' } : item));

      try {
        const { base64, mimeType } = await fileToBase64(img.file);
        const result = await generatePhotoMetadata(base64, mimeType);

        const metadata: PhotoMetadata = {
          title: result.title,
          keywords: result.keywords.join(', ')
        };

        setImages(prev => prev.map(item => item.id === img.id ? { 
          ...item, 
          status: 'completed', 
          metadata 
        } : item));
      } catch (err) {
        console.error(`Error processing ${img.file.name}:`, err);
        setImages(prev => prev.map(item => item.id === img.id ? { 
          ...item, 
          status: 'failed', 
          error: "API Limit reached or invalid image format."
        } : item));
      }
    }

    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const cancelProcessing = () => {
    stopRequested.current = true;
    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const reset = () => {
    setImages([]);
    setSearchTerm('');
    setAppState(AppState.HOME);
  };

  const copyToClipboard = (text: string, type: string) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(type);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  const removeImage = (id: string) => {
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const filteredImages = useMemo(() => {
    return images.filter(img => 
      img.file.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [images, searchTerm]);

  if (appState === AppState.SPLASH) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#1a1a2e]">
        <div className="relative animate-bounce">
          <Logo size="lg" />
          <div className="absolute inset-0 bg-blue-500/20 blur-3xl rounded-full"></div>
        </div>
        <h1 className="mt-8 text-5xl font-title font-bold tracking-[0.2em] text-white">OSMAN <span className="text-[#e94560]">METADATA</span></h1>
        <div className="mt-6 flex flex-col items-center gap-2">
          <p className="text-[#cccccc] font-medium tracking-widest uppercase text-sm">AI-Powered Stock SEO Engine</p>
          <div className="w-48 h-1 bg-[#0f3460] rounded-full overflow-hidden mt-2">
            <div className="h-full bg-gradient-to-r from-[#e94560] to-[#00d2ff] animate-[loading_2.5s_ease-in-out]"></div>
          </div>
          <p className="mt-8 text-xs text-white/40 italic">Developed by Abdullah Al Osman</p>
        </div>
        <style>{`
          @keyframes loading {
            0% { width: 0%; }
            100% { width: 100%; }
          }
        `}</style>
      </div>
    );
  }

