import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { AppState, ImageData, PhotoMetadata, ApiProvider } from './types';
import { Logo } from './components/Logo';
import { fileToBase64, downloadCSV } from './utils/fileUtils';
import { generatePhotoMetadata } from './services/geminiService';

const CONCURRENCY_LIMIT = 3; // Process 3 images at once for speed
const MAX_RETRIES = 2;

export default function App() {
  const [appState, setAppState] = useState<AppState>(AppState.SPLASH);
  const [images, setImages] = useState<ImageData[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const stopRequested = useRef(false);
  const pauseRef = useRef(false);
  const retryQueue = useRef<string[]>([]);

  // API Key Management
  const [apiKeys, setApiKeys] = useState<Record<ApiProvider, string>>({
    gemini: localStorage.getItem('osman_gemini_key') || '',
    groq: localStorage.getItem('osman_groq_key') || '',
    openai: localStorage.getItem('osman_openai_key') || ''
  });

  const [connectingProvider, setConnectingProvider] = useState<ApiProvider | null>(null);
  const [tempKey, setTempKey] = useState('');

  useEffect(() => {
    const timer = setTimeout(() => {
      setAppState(AppState.HOME);
    }, 2800);
    return () => clearTimeout(timer);
  }, []);

  const hasAnyKey = useMemo(() => {
    return Object.values(apiKeys).some(key => key && key.trim().length > 0);
  }, [apiKeys]);

  const saveApiKey = () => {
    if (connectingProvider) {
      localStorage.setItem(`osman_${connectingProvider}_key`, tempKey);
      setApiKeys(prev => ({ ...prev, [connectingProvider]: tempKey }));
      setConnectingProvider(null);
      setTempKey('');
    }
  };

  const disconnectApiKey = (provider: ApiProvider) => {
    localStorage.removeItem(`osman_${provider}_key`);
    setApiKeys(prev => ({ ...prev, [provider]: '' }));
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const selectedFiles = Array.from(e.target.files) as File[];

    if (images.length + selectedFiles.length > 500) {
      alert("Maximum 500 images allowed per batch.");
      return;
    }

    const newImages: ImageData[] = selectedFiles.map((file, index) => ({
      id: `${Date.now()}-${index}`,
      file,
      preview: URL.createObjectURL(file),
      status: 'pending'
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const processImage = async (img: ImageData, attempt = 0): Promise<void> => {
    if (stopRequested.current) return;

    // Handle Pause
    while (pauseRef.current) {
      await new Promise(r => setTimeout(r, 500));
      if (stopRequested.current) return;
    }

    setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'processing' } : item));

    try {
      const { base64, mimeType } = await fileToBase64(img.file);
      const result = await generatePhotoMetadata(base64, mimeType, apiKeys.gemini);

      const metadata: PhotoMetadata = {
        title: result.title,
        keywords: result.keywords.join(', ')
      };

      setImages(prev => prev.map(item => item.id === img.id ? { 
        ...item, 
        status: 'completed', 
        metadata 
      } : item));
    } catch (err) {
      if (attempt < MAX_RETRIES) {
        // Queue for retry at the end
        if (!retryQueue.current.includes(img.id)) {
          retryQueue.current.push(img.id);
        }
        setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'pending', error: `Retry ${attempt + 1}...` } : item));
      } else {
        setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'failed', error: "Final attempt failed." } : item));
      }
    }
  };

  const startProcessing = async () => {
    if (images.length === 0) return;
    setAppState(AppState.PROCESSING);
    setIsProcessing(true);
    setIsPaused(false);
    pauseRef.current = false;
    stopRequested.current = false;
    retryQueue.current = [];

    const pendingImages = images.filter(img => img.status === 'pending');
    let currentIndex = 0;

    const runBatch = async () => {
      const workers = [];
      while (currentIndex < pendingImages.length || retryQueue.current.length > 0) {
        if (stopRequested.current) break;

        // Priority to main pending list, then retry queue
        let targetImg = null;
        if (currentIndex < pendingImages.length) {
          targetImg = pendingImages[currentIndex++];
        } else if (retryQueue.current.length > 0) {
          const retryId = retryQueue.current.shift();
          targetImg = images.find(i => i.id === retryId);
        }

        if (targetImg) {
          const promise = processImage(targetImg).then(() => {
            workers.splice(workers.indexOf(promise), 1);
          });
          workers.push(promise);

          if (workers.length >= CONCURRENCY_LIMIT) {
            await Promise.race(workers);
          }
        } else {
          // Wait for workers if no more immediate work
          if (workers.length > 0) await Promise.race(workers);
          else break;
        }
      }
      await Promise.all(workers);
    };

    await runBatch();

    setIsProcessing(false);
    if (!stopRequested.current) {
      setAppState(AppState.RESULTS);
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    pauseRef.current = !pauseRef.current;
  };

  const stopProcessing = () => {
    stopRequested.current = true;
    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const clearBatch = () => {
    setImages([]);
    setAppState(AppState.HOME);
  };

  const reset = () => {
    setImages([]);
    setSearchTerm('');
    setAppState(AppState.HOME);
  };

  const copyToClipboard = (text: string, type: string) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(type);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  const filteredImages = useMemo(() => {
    return images.filter(img => 
      img.file.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [images, searchTerm]);

  const progress = useMemo(() => {
    const total = images.length;
    if (total === 0) return 0;
    const done = images.filter(img => img.status === 'completed' || img.status === 'failed').length;
    return Math.round((done / total) * 100);
  }, [images]);

  if (appState === AppState.SPLASH) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#0a0a0a]">
        <div className="relative animate-bounce">
          <Logo size="lg" />
        </div>
        <h1 className="mt-8 text-5xl font-title font-bold tracking-[0.2em] text-white">OSMAN <span className="text-[#e94560]">METADATA</span></h1>
        <div className="mt-6 flex flex-col items-center gap-2">
          <div className="w-48 h-1 bg-white/5 rounded-full overflow-hidden mt-2">
            <div className="h-full bg-[#00d2ff] animate-[loading_2.5s_ease-in-out]"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col font-sans text-white overflow-x-hidden">
      {/* Header */}
      <header className="px-8 py-4 border-b border-white/5 flex items-center justify-between sticky top-0 bg-[#0a0a0a]/90 backdrop-blur-xl z-50 shadow-2xl">
        <div className="flex items-center gap-5">
           <div className="hover:scale-110 transition-transform cursor-pointer" onClick={() => setAppState(AppState.HOME)}>
              <Logo size="sm" />
           </div>
           <div>
            <h1 className="text-xl font-title font-bold tracking-tight">OSMAN METADATA</h1>
            <p className="text-white/40 text-[9px] uppercase tracking-[0.2em]">Infrastructure Control Panel</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={() => setAppState(appState === AppState.SETTINGS ? AppState.HOME : AppState.SETTINGS)}
            className={`p-2.5 rounded-xl transition-all border ${appState === AppState.SETTINGS ? 'bg-[#00d2ff]/10 border-[#00d2ff] text-[#00d2ff]' : 'bg-white/5 border-white/10 text-white/60 hover:text-white'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>
          <div className="h-8 w-px bg-white/10 mx-2"></div>
          <div className="flex flex-col items-end">
             <span className={`text-[10px] font-bold uppercase flex items-center gap-1.5 ${hasAnyKey ? 'text-green-500' : 'text-yellow-500'}`}>
               <span className={`w-1.5 h-1.5 rounded-full animate-pulse ${hasAnyKey ? 'bg-green-500' : 'bg-yellow-500'}`}></span>
               {hasAnyKey ? 'System Online' : 'Awaiting Config'}
             </span>
             <span className="text-[9px] text-white/30 uppercase tracking-tighter">v1.0.0.STABLE</span>
          </div>
        </div>
      </header>

      {/* API Modal (Same) */}
      {connectingProvider && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in">
           <div className="bg-[#141414] border border-white/10 w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl">
              <h3 className="text-2xl font-bold mb-2 uppercase tracking-tight">Connect {connectingProvider}</h3>
              <p className="text-white/40 text-sm mb-8 leading-relaxed">Enter your private API key to enable specialized infrastructure logic.</p>
              <div className="space-y-6">
                <input type="password" placeholder="sk-...." value={tempKey} onChange={(e) => setTempKey(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:border-[#00d2ff] outline-none transition-all" />
                <div className="flex gap-4 pt-4">
                  <button onClick={saveApiKey} className="flex-grow bg-[#00d2ff] text-black font-bold py-4 rounded-2xl hover:bg-[#57e4ff] transition-all">Save & Initialize</button>
                  <button onClick={() => setConnectingProvider(null)} className="px-6 bg-white/5 text-white/40 border border-white/10 rounded-2xl">Cancel</button>
                </div>
              </div>
           </div>
        </div>
      )}

      {copyFeedback && (
        <div className="fixed top-24 left-1/2 transform -translate-x-1/2 bg-[#00d2ff] text-black px-8 py-3 rounded-xl shadow-2xl z-[100] font-bold border border-white/20">
          ✓ {copyFeedback} Copied!
        </div>
      )}

      <main className="flex-grow container mx-auto px-6 py-10">

        {appState === AppState.SETTINGS && (
          <div className="max-w-6xl mx-auto animate-fade-in">
             <div className="mb-12">
                <p className="text-[#e94560] text-xs font-bold uppercase tracking-[0.3em] mb-2">Infrastructure Control</p>
                <h2 className="text-5xl font-title font-bold">API Hub & Limits</h2>
             </div>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-12">
                {/* Gemini Card */}
                <div className="bg-[#141414] rounded-[2rem] border border-white/5 overflow-hidden shadow-2xl relative">
                   <div className="p-8 border-b border-white/5 flex items-center justify-between">
                      <div className="flex items-center gap-5">
                         <div className="w-14 h-14 bg-white/5 rounded-2xl flex items-center justify-center border border-white/10 text-white/40 font-bold text-2xl">G</div>
                         <div>
                            <h3 className="text-xl font-bold">Google Gemini</h3>
                            <p className={`text-[10px] font-bold uppercase tracking-widest flex items-center gap-2 mt-1 ${apiKeys.gemini ? 'text-green-500' : 'text-white/20'}`}>
                               <span className={`w-1.5 h-1.5 rounded-full ${apiKeys.gemini ? 'bg-green-500 animate-pulse' : 'bg-white/20'}`}></span>
                               {apiKeys.gemini ? 'SYSTEM CONNECTED' : 'NOT CONNECTED'}
                            </p>
                         </div>
