import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are an elite Adobe Stock Metadata Optimization Specialist. Your task is to analyze visual content with an expert eye for commercial stock photography appeal and SEO performance.

Task: Generate highly optimized, distinct metadata for the provided image.

Output Requirements:
Title (90-120 Characters):
- Create a compelling, detailed title.
- Ensure the title length is strictly between 90 and 120 characters.
- Focus on the main subject, action, context, environment, emotion, and aesthetic qualities (e.g., lighting, composition).
- Avoid all punctuation (commas, periods, exclamation marks, etc.) within the title.
- Keywords should be naturally integrated, not just a list.

Keywords (40 Keywords):
- Generate exactly 40 keywords.
- Relevance First: The first 10-15 keywords must be the most critical and directly descriptive of the image's primary elements.
- Include a strong mix of:
  Literal: Objects, colors, locations, people, actions.
  Conceptual: Emotions, themes (e.g., innovation, growth, tranquility, struggle, diversity, future).
  Technical: Lighting (e.g., "natural light", "backlit"), composition (e.g., "close up", "wide shot").
- Keywords should be single words or very short, natural phrases (max 3 words).
- All keywords must be comma-separated.

Constraints:
- Do NOT include any additional text, conversational phrases, or explanations outside the JSON block.
- Do NOT use generic terms like "photo", "image", "picture", "stock", "isolated", or "background".
- Ensure the JSON is perfectly valid.`;

export async function generatePhotoMetadata(
  base64Image: string, 
  mimeType: string, 
  modelName: string = 'gemini-3-flash-preview'
): Promise<ApiResponse> {
  // Use the mandatory process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image,
              mimeType: mimeType,
            },
          },
          {
            text: "Generate stock photography metadata in JSON format as requested.",
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: {
              type: Type.STRING,
              description: "Optimized title, 90-120 characters, no punctuation",
            },
            keywords: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Array of exactly 40 keywords",
            },
          },
          required: ["title", "keywords"],
        },
      },
    });

    // Directly access the .text property as per guidelines
    const text = response.text || '{}';
    return JSON.parse(text) as ApiResponse;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { AppState, ImageData, PhotoMetadata, ApiProvider, AppConfig } from './types';
import { Logo } from './components/Logo';
import { fileToBase64, downloadCSV } from './utils/fileUtils';
import { generatePhotoMetadata } from './services/geminiService';

const CONCURRENCY_LIMIT = 3; 
const MAX_RETRIES = 2;

const DEFAULT_CONFIG: AppConfig = {
  provider: 'gemini',
  model: 'gemini-3-flash-preview',
  keys: {
    gemini: '',
    groq: '',
    openai: ''
  }
};

export default function App() {
  const [appState, setAppState] = useState<AppState>(AppState.SPLASH);
  const [images, setImages] = useState<ImageData[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const [config, setConfig] = useState<AppConfig>(() => {
    const saved = localStorage.getItem('osman_app_config');
    return saved ? JSON.parse(saved) : DEFAULT_CONFIG;
  });

  const stopRequested = useRef(false);
  const pauseRef = useRef(false);
  const retryQueue = useRef<string[]>([]);

  useEffect(() => {
    localStorage.setItem('osman_app_config', JSON.stringify(config));
  }, [config]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setAppState(AppState.HOME);
    }, 2800);
    return () => clearTimeout(timer);
  }, []);

  const hasAnyKey = useMemo(() => {
    // Gemini key is mandatory from environment, so we treat it as always valid for UI logic
    if (config.provider === 'gemini') return true;
    const key = config.keys[config.provider];
    return typeof key === 'string' && key.trim().length > 0;
  }, [config]);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const selectedFiles = Array.from(e.target.files) as File[];

    if (images.length + selectedFiles.length > 500) {
      alert("Maximum 500 images allowed per batch.");
      return;
    }

    const newImages: ImageData[] = selectedFiles.map((file, index) => ({
      id: `${Date.now()}-${index}`,
      file,
      preview: URL.createObjectURL(file),
      status: 'pending'
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const processImage = async (img: ImageData, attempt = 0): Promise<void> => {
    if (stopRequested.current) return;

    // Handle Pause
    while (pauseRef.current) {
      await new Promise(r => setTimeout(r, 500));
      if (stopRequested.current) return;
    }

    setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'processing' } : item));

    try {
      const { base64, mimeType } = await fileToBase64(img.file);
      const result = await generatePhotoMetadata(base64, mimeType, config.model);

      const metadata: PhotoMetadata = {
        title: result.title,
        keywords: result.keywords.join(', ')
      };

      setImages(prev => prev.map(item => item.id === img.id ? { 
        ...item, 
        status: 'completed', 
        metadata 
      } : item));
    } catch (err) {
      if (attempt < MAX_RETRIES) {
        if (!retryQueue.current.includes(img.id)) {
          retryQueue.current.push(img.id);
        }
        setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'pending', error: `Retry ${attempt + 1}...` } : item));
      } else {
        setImages(prev => prev.map(item => item.id === img.id ? { ...item, status: 'failed', error: "Failed after multiple retries." } : item));
      }
    }
  };

  const startProcessing = async () => {
    if (images.length === 0) return;
    setAppState(AppState.PROCESSING);
    setIsProcessing(true);
    setIsPaused(false);
    pauseRef.current = false;
    stopRequested.current = false;
    retryQueue.current = [];

    const runBatch = async () => {
      const workers: Promise<void>[] = [];
      const pendingImages = images.filter(img => img.status === 'pending');
      let currentIndex = 0;

      while (currentIndex < pendingImages.length || retryQueue.current.length > 0) {
        if (stopRequested.current) break;

        let targetImg = null;
        if (currentIndex < pendingImages.length) {
          targetImg = pendingImages[currentIndex++];
        } else if (retryQueue.current.length > 0) {
          const retryId = retryQueue.current.shift();
          targetImg = images.find(i => i.id === retryId);
        }

        if (targetImg) {
          const promise = processImage(targetImg).then(() => {
            workers.splice(workers.indexOf(promise), 1);
          });
          workers.push(promise);
          if (workers.length >= CONCURRENCY_LIMIT) await Promise.race(workers);
        } else {
          if (workers.length > 0) await Promise.race(workers);
          else break;
        }
      }
      await Promise.all(workers);
    };

    await runBatch();

    setIsProcessing(false);
    if (!stopRequested.current) {
      setAppState(AppState.RESULTS);
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    pauseRef.current = !pauseRef.current;
  };

  const stopProcessing = () => {
    stopRequested.current = true;
    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const clearBatch = () => {
    setImages([]);
    setAppState(AppState.HOME);
  };

  const reset = () => {
    setImages([]);
    setSearchTerm('');
    setAppState(AppState.HOME);
  };

  const copyToClipboard = (text: string, type: string) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(type);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  const filteredImages = useMemo(() => {
    return images.filter(img => 
      img.file.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [images, searchTerm]);

  const progress = useMemo(() => {
    const total = images.length;
    if (total === 0) return 0;
    const done = images.filter(img => img.status === 'completed' || img.status === 'failed').length;
    return Math.round((done / total) * 100);
  }, [images]);

  if (appState === AppState.SPLASH) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#0a0a0a]">
        <div className="relative animate-bounce">
          <Logo size="lg" />
        </div>
        <h1 className="mt-8 text-5xl font-title font-bold tracking-[0.2em] text-white">OSMAN <span className="text-[#e94560]">METADATA</span></h1>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col font-sans text-white overflow-x-hidden">
      {/* Header */}
      <header className="px-8 py-4 border-b border-white/5 flex items-center justify-between sticky top-0 bg-[#0a0a0a]/90 backdrop-blur-xl z-50 shadow-2xl">
        <div className="flex items-center gap-5 cursor-pointer" onClick={() => setAppState(AppState.HOME)}>
           <Logo size="sm" />
           <div>
            <h1 className="text-xl font-title font-bold tracking-tight">OSMAN METADATA</h1>
            <p className="text-white/40 text-[9px] uppercase tracking-[0.2em]">Infrastructure Control Panel</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={() => setAppState(appState === AppState.SETTINGS ? AppState.HOME : AppState.SETTINGS)}
            className={`p-2.5 rounded-xl transition-all border ${appState === AppState.SETTINGS ? 'bg-[#00d2ff] text-black border-[#00d2ff]' : 'bg-white/5 border-white/10 text-white/60 hover:text-white'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>
          <div className="h-8 w-px bg-white/10 mx-2"></div>
          <div className="flex flex-col items-end">
             <span className={`text-xs font-bold uppercase flex items-center gap-1.5 ${hasAnyKey ? 'text-green-500' : 'text-yellow-500'}`}>
               <span className={`w-1.5 h-1.5 rounded-full animate-pulse ${hasAnyKey ? 'bg-green-500' : 'bg-yellow-500'}`}></span>
               {hasAnyKey ? 'System Online' : 'Key Required'}
             </span>
             <span className="text-[9px] text-white/30 uppercase tracking-tighter">v1.1.0.STABLE</span>
          </div>
        </div>
      </header>

      <main className="flex-grow container mx-auto px-6 py-10 relative">
        {copyFeedback && (
          <div className="fixed top-24 left-1/2 transform -translate-x-1/2 bg-[#00d2ff] text-black px-8 py-3 rounded-xl shadow-2xl z-[100] font-bold border border-white/20 animate-in fade-in slide-in-from-top-4">
            ✓ {copyFeedback} Copied!
          </div>
        )}

        {appState === AppState.SETTINGS && (
          <div className="max-w-3xl mx-auto animate-fade-in bg-[#141414] border border-white/10 rounded-[2.5rem] p-12 shadow-2xl">
             <div className="mb-10 text-center">
                <h2 className="text-4xl font-title font-bold mb-2 tracking-tight">System Configuration</h2>
                <p className="text-white/40 text-sm">Fine-tune your AI metadata engine parameters.</p>
             </div>

             <div className="space-y-8">
                <div className="space-y-4">
                  <label className="text-[10px] font-bold uppercase tracking-widest text-white/30">Primary AI Provider</label>
                  <div className="grid grid-cols-3 gap-4">
                    {(['gemini', 'groq', 'openai'] as ApiProvider[]).map((p) => (
                      <button
                        key={p}
                        onClick={() => setConfig({ ...config, provider: p, model: p === 'gemini' ? 'gemini-3-flash-preview' : config.model })}
                        className={`py-4 rounded-2xl font-bold uppercase text-xs transition-all border ${config.provider === p ? 'bg-[#00d2ff] text-black border-[#00d2ff]' : 'bg-white/5 border-white/10 text-white/40 hover:text-white'}`}
                      >
                        {p}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4">
                  <label className="text-[10px] font-bold uppercase tracking-widest text-white/30">Processing Model Name</label>
                  <input
                    type="text"
                    value={config.model}
                    onChange={(e) => setConfig({ ...config, model: e.target.value })}
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:border-[#00d2ff] outline-none transition-all"
                    placeholder="Enter model string..."
                  />
                </div>

                {config.provider !== 'gemini' && (
                  <div className="space-y-4">
                    <label className="text-[10px] font-bold uppercase tracking-widest text-white/30">{config.provider.toUpperCase()} API Key</label>
                    <input
                      type="password"
                      value={config.keys[config.provider]}
                      onChange={(e) => setConfig({ ...config, keys: { ...config.keys, [config.provider]: e.target.value } })}
                      className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:border-[#00d2ff] outline-none transition-all"
                      placeholder="Enter private API key..."
                    />
                  </div>
                )}

                <div className="pt-8 border-t border-white/5 flex gap-4">
                   <button onClick={() => setAppState(AppState.HOME)} className="flex-grow bg-[#00d2ff] text-black py-5 rounded-2xl font-bold shadow-xl active:scale-95 transition-all">Save Changes</button>
                   <button onClick={() => { setConfig(DEFAULT_CONFIG); setAppState(AppState.HOME); }} className="px-8 bg-white/5 text-white/40 py-5 rounded-2xl font-bold border border-white/10 hover:text-white transition-all">Reset</button>
                </div>
             </div>
          </div>
        )}

        {appState === AppState.HOME && (
          <div className="max-w-5xl mx-auto animate-fade-in text-center py-20">
            <div className="mb-12 inline-block p-10 bg-white/5 rounded-full border border-white/5 shadow-2xl relative">
              <div className="absolute inset-0 bg-[#00d2ff]/5 blur-3xl rounded-full"></div>
              <svg className="w-24 h-24 text-[#00d2ff] animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
