            <div className="flex flex-col items-center gap-8">
              <label className="group relative bg-[#00d2ff] hover:bg-[#57e4ff] text-black px-20 py-8 rounded-3xl font-bold text-3xl cursor-pointer transition-all shadow-2xl hover:scale-105 active:scale-95">
