              {images.length > 0 && (
                <div className="animate-in fade-in slide-in-from-bottom-4 flex flex-col items-center gap-6 mt-8">
                  <div className="bg-white/5 px-10 py-5 rounded-2xl border border-white/10 backdrop-blur-md">
