                    <button 
                      onClick={startProcessing} 
                      disabled={!hasAnyKey} 
                      className={`bg-white text-black font-title font-bold px-16 py-6 rounded-2xl transition-all flex items-center gap-4 shadow-2xl ${!hasAnyKey ? 'opacity-30 cursor-not-allowed' : 'hover:scale-105 active:scale-95'}`}
                    >
                      Start Analysis <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z"/></svg>
                    </button>
                    <button onClick={clearBatch} className="px-8 bg-white/5 text-white/40 font-bold rounded-2xl border border-white/10 hover:text-white hover:bg-white/10 transition-all">Clear</button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {appState === AppState.PROCESSING && (
          <div className="max-w-6xl mx-auto flex flex-col items-center animate-fade-in">
            {/* High Performance Progress UI */}
            <div className="relative w-96 h-96 mb-16 flex items-center justify-center">
              <div className="absolute inset-0 bg-[#00d2ff]/10 blur-[120px] rounded-full animate-pulse"></div>
              {/* Spinning Ring */}
              <div className="absolute inset-0 border-[16px] border-white/5 rounded-full"></div>
              <svg className="w-full h-full transform -rotate-90 relative z-10">
                <circle
                  cx="192" cy="192" r="172" stroke="#00d2ff" strokeWidth="16" fill="transparent"
                  strokeDasharray={1080}
                  strokeDashoffset={1080 - (1080 * progress) / 100}
                  strokeLinecap="round"
                  className="transition-all duration-700 ease-out drop-shadow-[0_0_15px_rgba(0,210,255,0.6)]"
                />
              </svg>
              <div className="absolute inset-0 flex flex-col items-center justify-center z-20">
                <span className="text-8xl font-bold font-title tracking-tighter leading-none">{progress}%</span>
                <span className="text-[12px] uppercase tracking-[0.5em] text-white/30 mt-6 font-bold">Analyzing Content</span>
              </div>
            </div>

            {/* Controls Bar */}
            <div className="flex gap-6 mb-16">
               <button onClick={togglePause} className={`px-12 py-5 rounded-2xl font-bold text-xs uppercase tracking-widest transition-all border ${isPaused ? 'bg-[#00d2ff] text-black border-[#00d2ff]' : 'bg-white/5 border-white/10 text-white/60 hover:text-white'}`}>
                {isPaused ? '▶ Resume' : '⏸ Pause'}
               </button>
               <button onClick={stopProcessing} className="px-12 py-5 rounded-2xl font-bold text-xs uppercase tracking-widest bg-red-500/10 text-red-500 border border-red-500/20 hover:bg-red-500 hover:text-white transition-all">
                ⏹ Stop Batch
               </button>
            </div>

            {/* Real-time Infrastructure Stream */}
            <div className="w-full bg-[#141414] rounded-[3rem] p-10 border border-white/5 shadow-3xl">
               <div className="flex justify-between items-center mb-10 border-b border-white/5 pb-8">
                  <h3 className="text-sm font-bold uppercase tracking-widest text-white/40">Infrastructure Stream</h3>
                  <div className="flex gap-8 items-center font-bold text-[10px] uppercase">
                     <span className="text-green-500/80">SUCCESS: {images.filter(img => img.status === 'completed').length}</span>
                     <span className="text-red-500/80">FAILED: {images.filter(img => img.status === 'failed').length}</span>
                  </div>
               </div>
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 max-h-[600px] overflow-y-auto pr-6 custom-scrollbar">
                {images.map(img => (
                  <div key={img.id} className={`p-6 rounded-[2rem] flex items-center gap-6 border transition-all duration-300 ${
                    img.status === 'completed' ? 'bg-white/[0.04] border-green-500/20' : 
                    img.status === 'processing' ? 'bg-[#00d2ff]/5 border-[#00d2ff]/40' : 
                    'bg-white/[0.02] border-white/5'
                  }`}>
                    <div className="relative flex-shrink-0 w-20 h-20">
                      <img src={img.preview} alt="preview" className="w-full h-full object-cover rounded-2xl border border-white/10" />
                      {img.status === 'processing' && (
                        <div className="absolute inset-0 bg-black/50 flex items-center justify-center rounded-2xl backdrop-blur-sm">
                          <div className="w-6 h-6 border-3 border-[#00d2ff] border-t-transparent rounded-full animate-spin"></div>
                        </div>
                      )}
                    </div>
                    <div className="flex flex-col flex-grow overflow-hidden">
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-xs font-bold truncate max-w-[180px] text-white/90 uppercase tracking-tighter">{img.file.name}</span>
                        <span className={`text-[9px] font-bold uppercase px-3 py-1 rounded-full ${
                          img.status === 'completed' ? 'bg-green-500/10 text-green-500' :
                          img.status === 'failed' ? 'bg-red-500/10 text-red-500' :
                          img.status === 'processing' ? 'bg-[#00d2ff]/10 text-[#00d2ff]' : 'text-white/20'
                        }`}>
                          {img.status === 'pending' && img.error ? 'QUEUED' : img.status}
                        </span>
                      </div>

                      {img.metadata ? (
                        <div className="animate-in fade-in slide-in-from-left-2">
                           <p className="text-[11px] font-bold text-white/80 line-clamp-1 italic mb-1">"{img.metadata.title}"</p>
                           <p className="text-[9px] text-white/40 truncate tracking-tight">{img.metadata.keywords}</p>
                        </div>
                      ) : (
                        <p className="text-[10px] text-white/20 mt-1 uppercase tracking-tighter">
                          {img.status === 'processing' ? 'Analyzing visual descriptors...' : 'Awaiting processing cycle...'}
                        </p>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {appState === AppState.RESULTS && (
          <div className="max-w-7xl mx-auto animate-fade-in">
            <div className="bg-[#141414] rounded-[2.5rem] p-12 mb-12 border border-white/5 shadow-2xl flex flex-col lg:flex-row items-center justify-between gap-10">
              <div className="text-center lg:text-left">
                <h2 className="text-5xl font-title font-bold mb-3 tracking-tight">Analysis Complete</h2>
                <p className="text-white/40 uppercase tracking-[0.3em] text-[10px] font-bold">
                  {images.filter(i => i.status === 'completed').length} ASSETS OPTIMIZED • BATCH EXPORT READY
