              </div>
              <div className="flex flex-wrap justify-center gap-6">
                <button 
                  onClick={() => downloadCSV(images)}
                  className="bg-[#00d2ff] hover:bg-[#57e4ff] text-black px-16 py-6 rounded-2xl font-bold flex items-center gap-4 shadow-3xl transition-all hover:-translate-y-1"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
                  Export CSV Report
                </button>
                <button onClick={reset} className="bg-white/5 hover:bg-white/10 text-white px-10 py-6 rounded-2xl font-bold transition-all border border-white/5">Start New Batch</button>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
              {filteredImages.map(img => (
                <div key={img.id} className="bg-[#141414] rounded-[2.5rem] overflow-hidden flex flex-col border border-white/5 group hover:border-[#00d2ff]/40 transition-all duration-500 shadow-2xl relative">
                  <div className="relative h-72 overflow-hidden">
                    <img src={img.preview} alt="preview" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black to-transparent opacity-80"></div>
                    <div className="absolute top-6 left-6">
                       <span className="bg-black/60 backdrop-blur-md px-5 py-2 rounded-2xl border border-white/10 text-[10px] font-bold text-white/90 uppercase tracking-tighter truncate max-w-[200px] block">
                        {img.file.name}
                       </span>
                    </div>
                  </div>

                  <div className="p-10 flex-grow flex flex-col">
                    {img.metadata ? (
                      <>
                        <div className="mb-8">
                           <div className="flex justify-between items-center mb-4">
                              <span className="text-[11px] uppercase tracking-widest text-[#00d2ff] font-bold">SEO Title</span>
                              <button 
                                onClick={() => copyToClipboard(img.metadata!.title, 'Title')}
                                className="text-white/30 hover:text-[#00d2ff] transition-all p-2 bg-white/5 rounded-xl border border-white/5"
                              >
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
                              </button>
                           </div>
                           <h4 className="text-lg font-bold text-white/95 leading-relaxed font-title italic">
                            {img.metadata.title}
                           </h4>
                        </div>

                        <div className="flex-grow">
                           <div className="flex justify-between items-center mb-4">
                              <span className="text-[11px] uppercase tracking-widest text-white/40 font-bold">SEO Keywords (40)</span>
                              <button 
                                onClick={() => copyToClipboard(img.metadata!.keywords, 'Keywords')}
                                className="text-white/30 hover:text-[#00d2ff] transition-all p-2 bg-white/5 rounded-xl border border-white/5"
                              >
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
                              </button>
                           </div>
                           <div className="h-44 overflow-y-auto bg-black/40 rounded-2xl p-6 border border-white/5 custom-scrollbar">
                              <div className="flex flex-wrap gap-2">
                                {img.metadata.keywords.split(',').map((kw, idx) => (
                                  <span key={idx} className="bg-white/[0.03] text-[10px] text-white/60 px-3 py-1.5 rounded-xl border border-white/5 hover:border-[#00d2ff]/30 transition-all uppercase font-bold tracking-tight">
                                    {kw.trim()}
                                  </span>
                                ))}
                              </div>
                           </div>
                        </div>
                      </>
                    ) : (
                      <div className="flex flex-col items-center justify-center py-24 text-center text-white/20">
                        <svg className="w-16 h-16 mb-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                        <p className="text-xs font-bold uppercase tracking-widest">Metadata Generation Failed</p>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="p-10 text-center border-t border-white/5 bg-[#0a0a0a]">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
           <p className="text-white/20 text-[10px] font-bold tracking-[0.4em] uppercase">Osman Infrastructure Suite • v1.1.0-STABLE</p>
           <p className="text-white/10 text-[10px] font-medium tracking-[0.2em] uppercase">
             Infrastructure Logic developed by <span className="text-[#00d2ff] font-bold">Abdullah Al Osman</span>
           </p>
        </div>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #00d2ff; }
        @keyframes fade-in { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fade-in 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        @keyframes loading { from { width: 0%; } to { width: 100%; } }
      `}</style>
    </div>
  );
}

export interface ImageData {
  id: string;
  file: File;
  preview: string;
  status: 'pending' | 'processing' | 'completed' | 'failed';
  metadata?: PhotoMetadata;
  error?: string;
  retryCount?: number;
}

export interface PhotoMetadata {
  title: string;
  keywords: string; // Comma separated list for CSV
}

export interface ApiResponse {
  title: string;
  keywords: string[];
}

export enum AppState {
  SPLASH = 'SPLASH',
  HOME = 'HOME',
  PROCESSING = 'PROCESSING',
  RESULTS = 'RESULTS',
  SETTINGS = 'SETTINGS'
}

export type ApiProvider = 'gemini' | 'groq' | 'openai';

export interface ApiConfig {
  provider: ApiProvider;
  model: string;
  apiKey: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are an elite Adobe Stock Metadata Optimization Specialist. Your task is to analyze visual content with an expert eye for commercial stock photography appeal and SEO performance.

Task: Generate highly optimized, distinct metadata for the provided image.

Output Requirements:
Title (90-120 Characters):
- Create a compelling, detailed title.
- Ensure the title length is strictly between 90 and 120 characters.
- Focus on the main subject, action, context, environment, emotion, and aesthetic qualities.
- Avoid all punctuation within the title.

Keywords (40 Keywords):
- Generate exactly 40 keywords.
- Relevance First: The first 10-15 keywords must be the most critical.
- All keywords must be comma-separated.

Constraints:
- Return ONLY valid JSON.
- Do NOT use generic terms like "photo", "image", "picture".`;

export async function generatePhotoMetadata(base64Image: string, mimeType: string, customApiKey?: string): Promise<ApiResponse> {
  const apiKey = customApiKey || process.env.API_KEY || '';
  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image,
              mimeType: mimeType,
            },
          },
          {
            text: "Generate stock photography metadata in JSON format as requested.",
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: {
              type: Type.STRING,
              description: "Optimized title, 90-120 characters, no punctuation",
            },
            keywords: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Array of exactly 40 keywords",
            },
          },
          required: ["title", "keywords"],
        },
      },
    });

    const text = response.text || '';
    return JSON.parse(text) as ApiResponse;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { AppState, ImageData, PhotoMetadata, ApiProvider } from './types';
import { Logo } from './components/Logo';
import { fileToBase64, downloadCSV } from './utils/fileUtils';
import { generatePhotoMetadata } from './services/geminiService';

const CONCURRENCY_LIMIT = 3; // Process 3 images at once to respect quota
const MAX_RETRIES = 2;

export default function App() {
  const [appState, setAppState] = useState<AppState>(AppState.SPLASH);
  const [images, setImages] = useState<ImageData[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const stopRequested = useRef(false);
  const pauseRef = useRef(false);
  const processingQueue = useRef<string[]>([]);
  const retryQueue = useRef<string[]>([]);

  // API Key Management
  const [apiKeys, setApiKeys] = useState<Record<ApiProvider, string>>({
    gemini: localStorage.getItem('osman_gemini_key') || '',
    groq: localStorage.getItem('osman_groq_key') || '',
    openai: localStorage.getItem('osman_openai_key') || ''
  });

  const [connectingProvider, setConnectingProvider] = useState<ApiProvider | null>(null);
  const [tempKey, setTempKey] = useState('');

  useEffect(() => {
    const timer = setTimeout(() => {
      setAppState(AppState.HOME);
    }, 2800);
    return () => clearTimeout(timer);
  }, []);

  const hasAnyKey = useMemo(() => {
    return Object.values(apiKeys).some(key => key && key.trim().length > 0);
  }, [apiKeys]);

  const saveApiKey = () => {
    if (connectingProvider) {
      localStorage.setItem(`osman_${connectingProvider}_key`, tempKey);
      setApiKeys(prev => ({ ...prev, [connectingProvider]: tempKey }));
      setConnectingProvider(null);
      setTempKey('');
    }
  };

  const disconnectApiKey = (provider: ApiProvider) => {
    localStorage.removeItem(`osman_${provider}_key`);
    setApiKeys(prev => ({ ...prev, [provider]: '' }));
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const selectedFiles = Array.from(e.target.files) as File[];

    if (images.length + selectedFiles.length > 500) {
      alert("Maximum 500 images allowed per batch.");
      return;
    }

    const newImages: ImageData[] = selectedFiles.map((file, index) => ({
      id: `${Date.now()}-${index}`,
      file,
      preview: URL.createObjectURL(file),
      status: 'pending',
      retryCount: 0
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const processSingleImage = async (imgId: string, isRetry = false) => {
    if (stopRequested.current) return;

    // Pause Logic
    while (pauseRef.current) {
      await new Promise(r => setTimeout(r, 500));
      if (stopRequested.current) return;
    }

    setImages(prev => prev.map(item => item.id === imgId ? { ...item, status: 'processing' } : item));

    const img = images.find(i => i.id === imgId);
    if (!img) return;

    try {
      const { base64, mimeType } = await fileToBase64(img.file);
      const result = await generatePhotoMetadata(base64, mimeType, apiKeys.gemini);

      const metadata: PhotoMetadata = {
        title: result.title,
        keywords: result.keywords.join(', ')
      };

      setImages(prev => prev.map(item => item.id === imgId ? { 
        ...item, 
        status: 'completed', 
        metadata 
      } : item));
    } catch (err) {
      console.error(`Error processing ${img.file.name}:`, err);

      const currentRetry = (img.retryCount || 0) + 1;
      if (currentRetry <= MAX_RETRIES) {
        setImages(prev => prev.map(item => item.id === imgId ? { 
          ...item, 
          status: 'pending', 
          retryCount: currentRetry,
          error: "Quota reached. Queued for retry."
        } : item));
        retryQueue.current.push(imgId);
      } else {
        setImages(prev => prev.map(item => item.id === imgId ? { 
          ...item, 
          status: 'failed', 
          error: "Final attempt failed. Quota exhausted."
        } : item));
      }
    }
  };

  const startProcessing = async () => {
    if (images.length === 0) return;
    setAppState(AppState.PROCESSING);
    setIsProcessing(true);
    setIsPaused(false);
    pauseRef.current = false;
    stopRequested.current = false;

    processingQueue.current = images.filter(img => img.status === 'pending').map(img => img.id);
    retryQueue.current = [];

    const runWorker = async () => {
      while (!stopRequested.current) {
        let nextId = processingQueue.current.shift();

        // If main queue is empty, check retry queue
        if (!nextId && retryQueue.current.length > 0) {
          // Small delay before retrying failed ones
          await new Promise(r => setTimeout(r, 2000));
          nextId = retryQueue.current.shift();
        }

        if (!nextId) break;
        await processSingleImage(nextId);
      }
    };

    // Run parallel workers
    const workers = Array.from({ length: CONCURRENCY_LIMIT }, () => runWorker());
    await Promise.all(workers);

    setIsProcessing(false);
    if (!stopRequested.current) {
      setAppState(AppState.RESULTS);
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    pauseRef.current = !isPaused;
  };

  const terminateProcess = () => {
    stopRequested.current = true;
    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

