export interface ImageData {
  id: string;
  file: File;
  preview: string;
  status: 'pending' | 'processing' | 'completed' | 'failed';
  metadata?: PhotoMetadata;
  error?: string;
  retryCount?: number;
}

export interface PhotoMetadata {
  title: string;
  keywords: string; // Comma separated list for CSV
}

export interface ApiResponse {
  title: string;
  keywords: string[];
}

export enum AppState {
  SPLASH = 'SPLASH',
  HOME = 'HOME',
  PROCESSING = 'PROCESSING',
  RESULTS = 'RESULTS',
  SETTINGS = 'SETTINGS'
}

export type ApiProvider = 'gemini' | 'groq' | 'openai';

export interface AppConfig {
  provider: ApiProvider;
  model: string;
  keys: {
    gemini: string; // Not used for entry but for structural consistency
    groq: string;
    openai: string;
  };
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ApiResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are an elite Adobe Stock Metadata Optimization Specialist. Your task is to analyze visual content with an expert eye for commercial stock photography appeal and SEO performance.

Task: Generate highly optimized, distinct metadata for the provided image.

Output Requirements:
Title (90-120 Characters):
- Create a compelling, detailed title.
- Ensure the title length is strictly between 90 and 120 characters.
- Focus on the main subject, action, context, environment, emotion, and aesthetic qualities.
- Avoid all punctuation within the title.

Keywords (40 Keywords):
- Generate exactly 40 keywords.
- Relevance First: The first 10-15 keywords must be the most critical.
- All keywords must be comma-separated.

Constraints:
- Return ONLY valid JSON.
- Do NOT use generic terms like "photo", "image", "picture".`;

export async function generatePhotoMetadata(
  base64Image: string, 
  mimeType: string, 
  modelName: string = 'gemini-3-flash-preview'
): Promise<ApiResponse> {
  // Always use process.env.API_KEY for Gemini
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image,
              mimeType: mimeType,
            },
          },
          {
            text: "Generate stock photography metadata in JSON format as requested.",
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: {
              type: Type.STRING,
              description: "Optimized title, 90-120 characters, no punctuation",
            },
            keywords: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Array of exactly 40 keywords",
            },
          },
          required: ["title", "keywords"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from model");

    return JSON.parse(text) as ApiResponse;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    // Rethrow to let App.tsx handle retry/429
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { AppState, ImageData, PhotoMetadata, ApiProvider, AppConfig } from './types';
import { Logo } from './components/Logo';
import { fileToBase64, downloadCSV } from './utils/fileUtils';
import { generatePhotoMetadata } from './services/geminiService';

const CONCURRENCY_LIMIT = 2; // Safer limit for free tier
const INITIAL_BACKOFF = 3000; // 3 seconds base for 429s

const DEFAULT_CONFIG: AppConfig = {
  provider: 'gemini',
  model: 'gemini-3-flash-preview',
  keys: {
    gemini: '',
    groq: '',
    openai: ''
  }
};

export default function App() {
  const [appState, setAppState] = useState<AppState>(AppState.SPLASH);
  const [images, setImages] = useState<ImageData[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const [config, setConfig] = useState<AppConfig>(() => {
    const saved = localStorage.getItem('osman_v1_config');
    return saved ? JSON.parse(saved) : DEFAULT_CONFIG;
  });

  const stopRequested = useRef(false);
  const pauseRef = useRef(false);
  const processingQueue = useRef<string[]>([]);
  const retryQueue = useRef<string[]>([]);
  const globalBackoffUntil = useRef<number>(0);

  useEffect(() => {
    localStorage.setItem('osman_v1_config', JSON.stringify(config));
  }, [config]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setAppState(AppState.HOME);
    }, 2800);
    return () => clearTimeout(timer);
  }, []);

  const hasConfigured = useMemo(() => {
    if (config.provider === 'gemini') return true; // env key assumed
    const key = config.keys[config.provider];
    return key && key.trim().length > 0;
  }, [config]);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const selectedFiles = Array.from(e.target.files) as File[];

    if (images.length + selectedFiles.length > 500) {
      alert("Maximum 500 images allowed per batch.");
      return;
    }

    const newImages: ImageData[] = selectedFiles.map((file, index) => ({
      id: `${Date.now()}-${index}`,
      file,
      preview: URL.createObjectURL(file),
      status: 'pending',
      retryCount: 0
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

  const processSingleImage = async (imgId: string) => {
    if (stopRequested.current) return;

    // Pause or Global Backoff Logic
    while (pauseRef.current || Date.now() < globalBackoffUntil.current) {
      if (Date.now() < globalBackoffUntil.current) {
        setImages(prev => prev.map(item => item.id === imgId ? { ...item, error: `Waiting for quota...` } : item));
      }
      await sleep(1000);
      if (stopRequested.current) return;
    }

    setImages(prev => prev.map(item => item.id === imgId ? { ...item, status: 'processing', error: undefined } : item));

    const img = images.find(i => i.id === imgId);
    if (!img) return;

    try {
      const { base64, mimeType } = await fileToBase64(img.file);

      let result;
      if (config.provider === 'gemini') {
        result = await generatePhotoMetadata(base64, mimeType, config.model);
      } else {
        // Fallback for other providers - using gemini logic for now as placeholders
        result = await generatePhotoMetadata(base64, mimeType, config.model);
      }

      const metadata: PhotoMetadata = {
        title: result.title,
        keywords: result.keywords.join(', ')
      };

      setImages(prev => prev.map(item => item.id === imgId ? { 
        ...item, 
        status: 'completed', 
        metadata,
        error: undefined
      } : item));
    } catch (err: any) {
      const isQuotaError = err.message?.includes('429') || err.status === 429 || JSON.stringify(err).includes('429');

      if (isQuotaError) {
        // Trigger global backoff to stop all workers
        const waitTime = INITIAL_BACKOFF * Math.pow(2, img.retryCount || 0);
        globalBackoffUntil.current = Date.now() + waitTime;

        setImages(prev => prev.map(item => item.id === imgId ? { 
          ...item, 
          status: 'pending', 
          retryCount: (item.retryCount || 0) + 1,
          error: `Quota exceeded. Retrying in ${Math.round(waitTime/1000)}s...`
        } : item));

        retryQueue.current.push(imgId);
      } else {
        setImages(prev => prev.map(item => item.id === imgId ? { 
          ...item, 
          status: 'failed', 
          error: "Analysis error. Technical failure."
        } : item));
      }
    }
  };

  const startProcessing = async () => {
    if (images.length === 0) return;
    setAppState(AppState.PROCESSING);
    setIsProcessing(true);
    setIsPaused(false);
    pauseRef.current = false;
    stopRequested.current = false;
    globalBackoffUntil.current = 0;

    processingQueue.current = images.filter(img => img.status === 'pending').map(img => img.id);
    retryQueue.current = [];

    const runWorker = async () => {
      while (!stopRequested.current) {
        let nextId = processingQueue.current.shift();

        if (!nextId && retryQueue.current.length > 0) {
          await sleep(2000); // Wait before grabbing from retry
          nextId = retryQueue.current.shift();
        }

        if (!nextId) break;
        await processSingleImage(nextId);
        await sleep(500); // Short throttle between requests
      }
    };

    const workers = Array.from({ length: CONCURRENCY_LIMIT }, () => runWorker());
    await Promise.all(workers);

    setIsProcessing(false);
    if (!stopRequested.current) {
      setAppState(AppState.RESULTS);
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    pauseRef.current = !isPaused;
  };

  const terminateProcess = () => {
    stopRequested.current = true;
    setIsProcessing(false);
    setAppState(AppState.RESULTS);
  };

  const clearAndReset = () => {
    setImages([]);
    setSearchTerm('');
    setAppState(AppState.HOME);
  };

  const copyToClipboard = (text: string, type: string) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(type);
    setTimeout(() => setCopyFeedback(null), 2000);
